import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1


def process(data, context):
    """Triggered from a message on a Cloud Pub/Sub topic.
    Args:
         data (dict): The dictionary with data specific to this type of message.
         context (google.cloud.functions.Context): The Cloud Functions event
          context. The `event_id` and `timestamp` attributes can be used to
          determine the sequence of messages within a function instance. For
          more information on Cloud Functions contexts, see https://cloud.google.com/functions/docs/contexts.
    """

    # Get the file name from the pubsub message
    filename = data['name']

    # Create a storage client object and get the bucket reference
    storage_client = storage.Client()
    bucket = storage_client.bucket(os.environ["BUCKET"])

    # Download the file to the local filesystem
    blob = bucket.blob(filename)
    blob.download_to_filename(filename)

    # Create a firestore client object and get the collection reference
    db = firestore.Client()
    collection = db.collection('files')

    # Upload the file to Firestore
    collection.add({'name': filename})

    # Publish the file name to Pub/Sub
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path(os.environ["PROJECT"], os.environ["TOPIC"])
    data = filename.encode('utf-8')
    future = publisher.publish(topic_path, data=data)

    # Delete the file from Cloud Storage
    blob.delete()